import{_ as o,o as t,c as a,U as e}from"./chunks/framework.82e57da9.js";const s="/AINotes/assets/1689683296176-148.f430eb6f.png",r="/AINotes/assets/1689683296175-127.c4e8ff65.png",p="/AINotes/assets/1689683296175-128.84da4843.jpeg",i="/AINotes/assets/1689683296175-129.53fda626.png",n="/AINotes/assets/1689683296175-130.5ced1813.png",c="/AINotes/assets/1689683296175-131.bcc9d517.png",l="/AINotes/assets/1689683296175-132.c0c47e47.jpeg",m="/AINotes/assets/1689683296176-133.c9df0a41.png",d="/AINotes/assets/1689683296176-134.e2bb60f0.png",g="/AINotes/assets/1689683296176-135.510ea82f.png",_="/AINotes/assets/1689683296176-136.8c4e163f.png",h="/AINotes/assets/1689683296176-137.ac40180d.png",f="/AINotes/assets/1689683296176-138.acc9a77d.png",A="/AINotes/assets/1689683296176-139.44ab7dfd.png",I="/AINotes/assets/1689683296176-140.5a3eb6ee.png",u="/AINotes/assets/1689683296176-141.d8d4269a.png",b="/AINotes/assets/1689683296176-142.5c470d49.png",N="/AINotes/assets/1689683492113-189.d16e84b2.png",L="/AINotes/assets/1689683296176-144.ae99cd46.png",q="/AINotes/assets/1689683532915-192.e956bfb0.png",k="/AINotes/assets/1689683543465-195.32a4154c.png",D="/AINotes/assets/1689683553904-198.701a941b.png",V=JSON.parse('{"title":"Leonardo.AI注册","description":"","frontmatter":{},"headers":[],"relativePath":"Document/AI绘画工具/Leonardo.AI绘画工具/Leonardo.AI注册.md","filePath":"Document/AI绘画工具/Leonardo.AI绘画工具/Leonardo.AI注册.md","lastUpdated":1689691980000}'),S={name:"Document/AI绘画工具/Leonardo.AI绘画工具/Leonardo.AI注册.md"},P=e('<h1 id="leonardo-ai注册" tabindex="-1">Leonardo.AI注册 <a class="header-anchor" href="#leonardo-ai注册" aria-label="Permalink to &quot;Leonardo.AI注册&quot;">​</a></h1><h2 id="写在前面的话" tabindex="-1">写在前面的话 <a class="header-anchor" href="#写在前面的话" aria-label="Permalink to &quot;写在前面的话&quot;">​</a></h2><p>这款软件无需使用魔法上网，国内用户直接可以使用，生成的图片质量也非常不错，可以作为Midjourney的替代品。</p><p>Leonardo是一个AI绘画社区，同时也是一个AI绘画工具。</p><p>Leonardo是基于Stable Diffusion的网站，同时深度集成了Stable Diffusion的各种插件，比如ControlNET的openpose姿势参考、局部重绘、prompt提示等等，甚至还提供了傻瓜式在线训练自己模型的功能。</p><p>对Stable Diffusion了解比较多的人可能会知道一个Stable Diffusion模型分享社区–<a href="http://civitai.com/" target="_blank" rel="noreferrer">civitai.com</a>（魔法）。而Leonardo更像是Civtai和Stable Diffusion的集合体。</p><h3 id="纯文字教程" tabindex="-1">纯文字教程 <a class="header-anchor" href="#纯文字教程" aria-label="Permalink to &quot;纯文字教程&quot;">​</a></h3><p>Leonardo注册教程：</p><ol><li>打开官网 <a href="https://leonardo.ai/" target="_blank" rel="noreferrer">https://leonardo.ai/</a> ，在输入框中输入邮箱，点击右侧&quot;Count me in&quot;加入。</li><li>加入Discord社区，选择中文语言，同意使用规则。</li><li>在左侧找到&quot;priority-early-access&quot;频道，点击蓝色链接，填写白名单资料并提交。</li></ol><p>Leonardo使用教程：</p><ol><li>打开官网 <a href="https://leonardo.ai/" target="_blank" rel="noreferrer">https://leonardo.ai/</a> ，点击右上角的&quot;Launch App&quot;。</li><li>点击&quot;Sign Up&quot;，输入邮箱和密码注册，验证邮箱即可登录。</li><li>登录后点击左边菜单的&quot;AI Image Generation&quot;，即可开始生成图片。</li></ol><p>生成的图片可以进行精修，以获得更美观的效果。Leonardo集成了很多训练好的模型，用户可以选择适合自己的模型进行绘画。在社区里，可以看到很多其他用户创作的优秀作品，并可以参照这些作品使用。此外，用户也可以训练自己的模型。</p><p>Leonardo还有很多其他功能，大家可以慢慢探索体验。</p><p>平台采用代币制，每人每天有250个token，渲染一张图大概需要3~8个token，如果不是高频使用，一天的token绝对够用。</p><p>下面是详细的图文注册教程</p><h3 id="eonardo-ai注册图文教程" tabindex="-1"><strong>eonardo.ai注册图文教程</strong> <a class="header-anchor" href="#eonardo-ai注册图文教程" aria-label="Permalink to &quot;**eonardo.ai注册图文教程**&quot;">​</a></h3><p>首先打开官网地址：<a href="https://leonardo.ai/" target="_blank" rel="noreferrer">https://leonardo.ai/</a> 然后在输入框中输入你的邮箱，点击右侧Count me in 加入。</p><p><img src="'+s+'" alt="img"></p><p>然后加入Discord社区，Discord也是用midjourney那个软件，这里需要用一下魔法。</p><p><img src="'+r+'" alt="img"></p><p>点击加入，然后可以选择语言，就选一个中文就可以了，第二个可以跳过。</p><p><img src="'+p+'" alt="img"></p><p><img src="'+i+'" alt="img"></p><p>然后后面按还有两个选择，按图下选就行，选择完成之后还要同意一下使用规则。</p><p><img src="'+n+'" alt="img"></p><p><img src="'+c+'" alt="img"></p><p><img src="'+l+'" alt="img"></p><p><img src="'+m+'" alt="img"></p><p>然后在左侧找到 priority-early-access 这个频道，然后点击这个蓝色链接。</p><p><img src="'+d+'" alt="img"></p><p>然后填写白名单资料，填写完成点击提交就可以了。</p><p><img src="'+g+'" alt="img"></p><p><img src="'+_+'" alt="img"></p><h3 id="eonardo-ai使用图文教程" tabindex="-1"><strong>eonardo.ai使用图文教程</strong> <a class="header-anchor" href="#eonardo-ai使用图文教程" aria-label="Permalink to &quot;**eonardo.ai使用图文教程**&quot;">​</a></h3><p>注册完成之后，我们再次打开官网，<a href="https://leonardo.ai/" target="_blank" rel="noreferrer">https://leonardo.ai/</a> ，点击右上角的Launch App。</p><p><img src="'+h+'" alt="img"></p><p>然后按步骤点击。</p><p><img src="'+f+'" alt="img"></p><p><img src="'+A+'" alt="img"></p><p><img src="'+I+'" alt="img"></p><p>点sign up，再输入邮箱和密码注册，然后邮箱会有一个验证码，登录即可。</p><p><img src="'+u+'" alt="img"></p><p><img src="'+b+'" alt="img"></p><p>登录之后点击左边菜单的 AI lmage Generation</p><p><img src="'+N+'" alt="img"></p><p>然后就可以开始生成图片了。</p><p><img src="'+L+'" alt="img"></p><p>生成后的图片还能进行精修，精修之后才好看。</p><p><img src="'+q+'" alt="img"></p><p>Leonardo集成了很多训练好的模型。你可以选择适合的模型进行绘画。在社区里，你可以看到非常多的，由其他用户创作的优秀作品，基于这些作品，你可以直接参照使用。有意思的是，你还可以训练自己的模型。</p><p>Leonardo还有非常多的功能，大家可以慢慢体验~</p><p><img src="'+k+'" alt="img"></p><p>平台采用代币制，每人每天250个token，渲染一张图大概3~8token不等，基本上如果不是高频式的疯狂用，一天绝对够了。</p><p><img src="'+D+'" alt="img"></p>',54),x=[P];function T(y,C,v,j,$,E){return t(),a("div",null,x)}const B=o(S,[["render",T]]);export{V as __pageData,B as default};
